using Microsoft.AspNetCore.Diagnostics;
using Microsoft.AspNetCore.Mvc;

namespace YourApp;

/// <summary>
/// Maps known exception types to RFC 7807 Problem Details responses.
/// Unhandled exceptions return a generic 500 with no leaked internals.
/// </summary>
public sealed class GlobalExceptionHandler : IExceptionHandler
{
    private readonly ILogger<GlobalExceptionHandler> _logger;

    public GlobalExceptionHandler(ILogger<GlobalExceptionHandler> logger)
    {
        _logger = logger;
    }

    public async ValueTask<bool> TryHandleAsync(
        HttpContext httpContext,
        Exception exception,
        CancellationToken cancellationToken)
    {
        var (statusCode, title) = exception switch
        {
            KeyNotFoundException   => (StatusCodes.Status404NotFound,    "Not Found"),
            ArgumentException      => (StatusCodes.Status400BadRequest,  "Bad Request"),
            InvalidOperationException => (StatusCodes.Status409Conflict, "Conflict"),
            _ => (StatusCodes.Status500InternalServerError, "Internal Server Error")
        };

        _logger.LogError(exception, "Unhandled exception ({ExceptionType})", exception.GetType().Name);

        var problemDetails = new ProblemDetails
        {
            Status = statusCode,
            Title  = title,
            // Only surface the message for client errors; hide internals for 500s.
            Detail = statusCode < 500 ? exception.Message : "An unexpected error occurred."
        };

        httpContext.Response.StatusCode = statusCode;
        await httpContext.Response.WriteAsJsonAsync(problemDetails, cancellationToken);

        return true; // Signal that the exception was handled.
    }
}

// ----- Add these lines to your Program.cs -----

// 1. Register services (before builder.Build())
builder.Services.AddProblemDetails();
builder.Services.AddExceptionHandler<GlobalExceptionHandler>();

// 2. Add middleware (after builder.Build(), before app.MapXxx())
app.UseExceptionHandler();

// That's it — every unhandled exception now returns Problem Details JSON
// without any per-endpoint try-catch.

